import{_ as a,a as d}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as e,o,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Додавання каналу pCloud","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/pcloud.md","filePath":"uk-UA/upload/pcloud.md","lastUpdated":1781962217000}'),s={name:"uk-UA/upload/pcloud.md"};function p(n,t,r,c,h,u){return o(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="додавання-каналу-pcloud" tabindex="-1">Додавання каналу pCloud <a class="header-anchor" href="#додавання-каналу-pcloud" aria-label="Permalink to &quot;Додавання каналу pCloud&quot;">​</a></h1><h2 id="наикраще-підходить-якщо" tabindex="-1">Найкраще підходить, якщо <a class="header-anchor" href="#наикраще-підходить-якщо" aria-label="Permalink to &quot;Найкраще підходить, якщо&quot;">​</a></h2><ul><li>У вас є обліковий запис pCloud і ви хочете, щоб ImgBed зберігав зображення в pCloud.</li><li>Вам підходить використання email і пароля pCloud як облікових даних каналу.</li></ul><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Email облікового запису pCloud</td><td>Для входу в pCloud API</td></tr><tr><td>Пароль pCloud</td><td>Для входу в pCloud API</td></tr><tr><td>API host</td><td>Типово <code>api.pcloud.com</code>. Для акаунтів у ЄС можна використовувати <code>eapi.pcloud.com</code>.</td></tr><tr><td>Storage directory</td><td>Місце зберігання файлів. Типово <code>imgbed</code>.</td></tr></tbody></table><h2 id="де-додати-канал" tabindex="-1">Де додати канал <a class="header-anchor" href="#де-додати-канал" aria-label="Permalink to &quot;Де додати канал&quot;">​</a></h2><ol><li>Відкрийте системні налаштування.</li><li>Відкрийте налаштування завантаження.</li><li>Натисніть <code>Add Channel</code> у правому верхньому куті.</li><li>Виберіть <code>pCloud</code>.</li></ol><h2 id="поля-налаштування" tabindex="-1">Поля налаштування <a class="header-anchor" href="#поля-налаштування" aria-label="Permalink to &quot;Поля налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Призначення</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Channel name</td><td>Ідентифікує цей pCloud-канал, наприклад <code>Personal pCloud</code></td><td>Так</td></tr><tr><td>Account email</td><td>Email для входу в pCloud</td><td>Так</td></tr><tr><td>Password</td><td>Ваш пароль pCloud</td><td>Так</td></tr><tr><td>API host</td><td>pCloud API host. Типово <code>api.pcloud.com</code>.</td><td>Ні</td></tr><tr><td>Storage directory</td><td>Директорія для зберігання файлів. Типово <code>imgbed</code>.</td><td>Ні</td></tr></tbody></table><p>Виберіть API host відповідно до регіону акаунта:</p><table tabindex="0"><thead><tr><th>Регіон акаунта</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><ol><li>Відкрийте налаштування завантаження.</li><li>Натисніть <code>Add Channel</code>.</li><li>Виберіть <code>pCloud</code>.</li><li>Введіть зрозумілу назву каналу.</li><li>Введіть email акаунта pCloud.</li><li>Введіть пароль pCloud.</li><li>Залиште API host як <code>api.pcloud.com</code> або використайте <code>eapi.pcloud.com</code> для акаунтів у ЄС.</li><li>Залиште storage directory як <code>imgbed</code> або змініть на потрібну папку.</li><li>Збережіть канал.</li></ol><p><img src="'+a+'" alt="Налаштування каналу" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Очікуваний результат</th></tr></thead><tbody><tr><td>Картка каналу</td><td>Картка pCloud-каналу з&#39;являється після збереження.</td></tr><tr><td>Перемикач каналу</td><td>Перемикач на картці залишається ввімкненим.</td></tr><tr><td>Показ email</td><td>На картці показано підключений email pCloud.</td></tr><tr><td>Запит квоти</td><td>Після успішного запиту показується використана й загальна місткість.</td></tr><tr><td>Тестове завантаження</td><td>Тестове зображення з&#39;являється в налаштованій директорії pCloud.</td></tr></tbody></table><p><img src="'+d+`" alt="Успішний запит квоти" loading="lazy"></p><h2 id="усунення-несправностеи" tabindex="-1">Усунення несправностей <a class="header-anchor" href="#усунення-несправностеи" aria-label="Permalink to &quot;Усунення несправностей&quot;">​</a></h2><h3 id="чому-не-oauth2" tabindex="-1">Чому не OAuth2? <a class="header-anchor" href="#чому-не-oauth2" aria-label="Permalink to &quot;Чому не OAuth2?&quot;">​</a></h3><p>pCloud OAuth2 типово не є self-service. Потрібно написати в pCloud і попросити ввімкнути його.</p><p>Поточний OAuth2 flow pCloud також не підтримує workflow короткочасних upload links, потрібний ImgBed, тому цей канал використовує вхід через email і пароль акаунта.</p><h3 id="якии-api-host-використовувати" tabindex="-1">Який API Host використовувати? <a class="header-anchor" href="#якии-api-host-використовувати" aria-label="Permalink to &quot;Який API Host використовувати?&quot;">​</a></h3><p>Типово:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>Для акаунтів у ЄС:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Підготувати email і пароль pCloud</span></span>
<span class="line"><span>-&gt; Відкрити налаштування завантаження</span></span>
<span class="line"><span>-&gt; Додати канал</span></span>
<span class="line"><span>-&gt; Вибрати pCloud</span></span>
<span class="line"><span>-&gt; Заповнити назву каналу / email / пароль</span></span>
<span class="line"><span>-&gt; Залишити API host як api.pcloud.com, якщо акаунт не в Європі</span></span>
<span class="line"><span>-&gt; Залишити storage directory як imgbed, якщо не потрібна інша папка</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Запитати квоту</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення</span></span></code></pre></div>`,28)])])}const C=e(s,[["render",p]]);export{g as __pageData,C as default};
